import React,
{
 useState
} from "react";

import axios from "axios";
import Api from "../api/Api";

import {
 useLocation,
 useNavigate
}
from "react-router-dom";

function VerifyOtp() {

 const [otp,setOtp] =
 useState("");

 const location =
 useLocation();

 const navigate =
 useNavigate();

 const mobile =
 location.state?.mobile;

 const handleVerify =
 async (e) => {

  e.preventDefault();

  try {

   const res =
   await axios.post(
    Api.verify_otp,
    {
      mobile,
      otp
    }
   );

   localStorage.setItem(
    "token",
    res.data.token
   );

   localStorage.setItem(
    "role",
    res.data.role
   );

   if(
    res.data.role
    === "admin"
   ){
    navigate("/admin");
   }

   else if(
    res.data.role
    === "driver"
   ){
    navigate(
     "/driver"
    );
   }

   else{
    navigate(
     "/supervisor"
    );
   }

  }

  catch(err){

   alert(
    err.response?.data
    ?.message
   );

  }

 };

 return (
  <form
   onSubmit={
    handleVerify
   }
  >

   <input
    value={otp}
    onChange={(e)=>
     setOtp(
      e.target.value
     )
    }
   />

   <button>
    Verify OTP
   </button>

  </form>
 );
}

export default VerifyOtp;
